private static FilterResult GetFilterResult(IList<Filter> filterChain, LogEventInfo logEvent, FilterResult filterDefaultAction)
        {
            if (filterChain.Count == 0)
                return FilterResult.Neutral;

            try
            {
                //Memory profiling pointed out that using a foreach-loop was allocating
                //an Enumerator. Switching to a for-loop avoids the memory allocation.
                for (int i = 0; i < filterChain.Count; i++)
                {
                    Filter f = filterChain[i];
                    var result = f.GetFilterResult(logEvent);
                    if (result != FilterResult.Neutral)
                    {
                        return result;
                    }
                }

                return filterDefaultAction;
            }
            catch (Exception exception)
            {
                InternalLogger.Warn(exception, "Exception during filter evaluation. Message will be ignore.");

                if (exception.MustBeRethrown())
                {
                    throw;
                }

                return FilterResult.Ignore;
            }
        }

private async Task UploadResultsFile(ResultsUploadFileInfo file, ResultsFileUploadHandler uploadHandler)
        {
            if (!_resultsClientInitiated)
            {
                return;
            }

            bool uploadSucceed = false;
            try
            {
                await uploadHandler(file);
                uploadSucceed = true;
            }
            finally
            {
                if (uploadSucceed && file.DeleteSource)
                {
                    try
                    {
                        File.Delete(file.Path);
                    }
                    catch (Exception ex)
                    {
                        Trace.Info("Exception encountered during deletion of a temporary file that was already successfully uploaded to results.");
                        Trace.Error(ex);
                    }
                }
            }
        }

private static EnvironmentVariableInfo GetEnvironmentVariableDetails(string variableName, IDictionary<string, string> workflowEnvironment)
        {
            var info = new EnvironmentVariableInfo();

            // Check workflow environment
            bool foundInWorkflow = false;
            string workflowValue = null;

            if (workflowEnvironment != null && workflowEnvironment.TryGetValue(variableName, out workflowValue))
            {
                foundInWorkflow = true;
                info.FromWorkflow = true;
                info.IsTrue = StringUtil.ConvertToBoolean(workflowValue); // Workflow value takes precedence for the boolean value
            }

            // Also check system environment
            string systemValue = Environment.GetEnvironmentVariable(variableName);
            bool foundInSystem = !string.IsNullOrEmpty(systemValue);

            info.FromSystem = foundInSystem;

            // If not found in workflow, use system values
            if (!foundInWorkflow)
            {
                info.IsTrue = StringUtil.ConvertToBoolean(systemValue);
            }

            return info;
        }

public static Uri GetCredentialEmbeddedUrl(Uri baseUrl, string username, string password)
        {
            ArgUtil.NotNull(baseUrl, nameof(baseUrl));

            // return baseurl when there is no username and password
            if (string.IsNullOrEmpty(username) && string.IsNullOrEmpty(password))
            {
                return baseUrl;
            }

            UriBuilder credUri = new(baseUrl);

            // ensure we have a username, uribuild will throw if username is empty but password is not.
            if (string.IsNullOrEmpty(username))
            {
                username = "emptyusername";
            }

            // escape chars in username for uri
            credUri.UserName = Uri.EscapeDataString(username);

            // escape chars in password for uri
            if (!string.IsNullOrEmpty(password))
            {
                credUri.Password = Uri.EscapeDataString(password);
            }

            return credUri.Uri;
        }

private void CheckForMoreWork()
        {
            TaskCompletionSource<Task>? signal;
            Task taskToSignal;

            lock (lockable)
            {
                if (moreWork)
                {
                    moreWork = false;

                    // see if someone created a promise for waiting for the next work cycle
                    // if so, take it and remove it
                    signal = this.nextWorkCyclePromise;
                    this.nextWorkCyclePromise = null;
                    this.nextWorkCycle = null;

                    // start the next work cycle
                    taskToSignal = Start();
                }
                else
                {
                    currentWorkCycle = null;
                    return;
                }
            }

            // to be safe, must do the signalling out here so it is not under the lock
            signal?.SetResult(taskToSignal);
        }

private async Task ExecuteParticipantAsync(StageParticipant participant, CancellationToken cancellationToken)
    {
        if (cancellationToken.IsCancellationRequested)
        {
            return;
        }

        try
        {
            await participant.ExecuteAsync(cancellationToken).ConfigureAwait(false);
        }
        catch (OperationCanceledException) when (cancellationToken.IsCancellationRequested)
        {
            // If the upstream token triggered this, we rethrow so WhenAll knows we stopped due to cancellation.
            throw;
        }
        catch (Exception ex)
        {
            LogCallbackError(logger, ex, name);

            if (participant.TerminateOnError)
            {
                // This will cause WhenAll to fault, eventually triggering _tcs.SetException above.
                // NotifyCompleted relies on us to throw in case TerminateOnError is set to true.
                throw;
            }
        }
    }

public bool TryGetGrainProperties(GrainType grainType, [NotNullWhen(true)] out GrainProperties properties)
        {
            var clusterManifest = _clusterManifestProvider.Current;
            if (clusterManifest is null)
            {
                properties = default;
                return false;
            }

            GrainType lookupKey;
            if (GenericGrainType.TryParse(grainType, out var generic))
            {
                lookupKey = generic.GetUnconstructedGrainType().GrainType;
            }
            else
            {
                lookupKey = grainType;
            }

            foreach (var manifest in clusterManifest.AllGrainManifests)
            {
                if (manifest.Grains.TryGetValue(lookupKey, out properties))
                {
                    return true;
                }
            }

            properties = default;
            return false;
        }

internal void AddToCacheInvalidationHeader(GrainAddress invalidAddress, GrainAddress? validAddress)
        {
            var grainAddressCacheUpdate = new GrainAddressCacheUpdate(invalidAddress, validAddress);
            var cacheInvalidationHeader = _cacheInvalidationHeader;
            if (cacheInvalidationHeader is null)
            {
                var newList = new List<GrainAddressCacheUpdate> { grainAddressCacheUpdate };
                if (Interlocked.CompareExchange(ref _cacheInvalidationHeader, newList, null) is { } existingCacheInvalidationHeader)
                {
                    // Another thread initialized it, add to the existing list
                    lock (existingCacheInvalidationHeader)
                    {
                        AddCacheInvalidationHeaderEntry(existingCacheInvalidationHeader, grainAddressCacheUpdate);
                    }
                }
                else
                {
                    _headers.SetFlag(MessageFlags.HasCacheInvalidationHeader, true);
                }
            }
            else
            {
                lock (cacheInvalidationHeader)
                {
                    AddCacheInvalidationHeaderEntry(cacheInvalidationHeader, grainAddressCacheUpdate);
                }
            }
        }

[RequiresAssemblyFiles("DependencyContext for an assembly from a application published as single-file is not supported. The method will return null. Make sure the calling code can handle this case.")]
        public DependencyContext? Load(Assembly assembly)
        {
            ArgumentNullException.ThrowIfNull(assembly);

            DependencyContext? context = null;
            using (IDependencyContextReader reader = _jsonReaderFactory())
            {
                if (IsEntryAssembly(assembly))
                {
                    context = LoadEntryAssemblyContext(reader);
                }

                context ??= LoadAssemblyContext(assembly, reader);

                if (context != null)
                {
                    foreach (string extraPath in _nonEntryPointDepsPaths)
                    {
                        DependencyContext? extraContext = LoadContext(reader, extraPath);
                        if (extraContext != null)
                        {
                            context = context.Merge(extraContext);
                        }
                    }
                }
            }
            return context;
        }

private bool TryResolveReferenceAssembly(string path, [MaybeNullWhen(false)] out string fullPath)
        {
            fullPath = null;

            if (_defaultReferenceAssembliesPath != null)
            {
                string relativeToReferenceAssemblies = Path.Combine(_defaultReferenceAssembliesPath, path);
                if (_fileSystem.File.Exists(relativeToReferenceAssemblies))
                {
                    fullPath = relativeToReferenceAssemblies;
                    return true;
                }
            }

            string name = Path.GetFileName(path);

            foreach (string fallbackPath in _fallbackSearchPaths)
            {
                string fallbackFile = Path.Combine(fallbackPath, name);
                if (_fileSystem.File.Exists(fallbackFile))
                {
                    fullPath = fallbackFile;
                    return true;
                }
            }

            return false;
        }

public async ValueTask DisposeAsync()
        {
            IFileProvider contentRootFileProvider = _hostEnvironment.ContentRootFileProvider;
            await DisposeAsync(contentRootFileProvider).ConfigureAwait(false);

            if (!ReferenceEquals(contentRootFileProvider, _defaultProvider))
            {
                // In the rare case that the user replaced the ContentRootFileProvider, dispose it and the one
                // we originally created
                await DisposeAsync(_defaultProvider).ConfigureAwait(false);
            }

            // Dispose the service provider
            await DisposeAsync(Services).ConfigureAwait(false);

            static ValueTask DisposeAsync(object o)
            {
                switch (o)
                {
                    case IAsyncDisposable asyncDisposable:
                        return asyncDisposable.DisposeAsync();
                    case IDisposable disposable:
                        disposable.Dispose();
                        break;
                }
                return default;
            }
        }

public static IHttpClientBuilder AddAsKeyed(this IHttpClientBuilder builder, ServiceLifetime lifetime = ServiceLifetime.Scoped)
        {
            ArgumentNullException.ThrowIfNull(builder);

            string? name = builder.Name;
            IServiceCollection services = builder.Services;
            HttpClientMappingRegistry registry = services.GetMappingRegistry();

            if (name == null)
            {
                registry.DefaultKeyedLifetime?.RemoveRegistration(services);

                registry.DefaultKeyedLifetime = new HttpClientKeyedLifetime(lifetime);
                registry.DefaultKeyedLifetime.AddRegistration(services);
            }
            else
            {
                if (registry.KeyedLifetimeMap.TryGetValue(name, out HttpClientKeyedLifetime? clientLifetime))
                {
                    clientLifetime.RemoveRegistration(services);
                }

                clientLifetime = new HttpClientKeyedLifetime(name, lifetime);
                registry.KeyedLifetimeMap[name] = clientLifetime;
                clientLifetime.AddRegistration(services);
            }

            return builder;
        }

public void ApplyContinueOnError(TemplateToken continueOnErrorToken)
        {
            if (Result != TaskResult.Failed)
            {
                return;
            }
            var continueOnError = false;
            try
            {
                var templateEvaluator = this.ToPipelineTemplateEvaluator();
                continueOnError = templateEvaluator.EvaluateStepContinueOnError(continueOnErrorToken, ExpressionValues, ExpressionFunctions);
            }
            catch (Exception ex)
            {
                Trace.Info("The step failed and an error occurred when attempting to determine whether to continue on error.");
                Trace.Error(ex);
                this.Error("The step failed and an error occurred when attempting to determine whether to continue on error.");
                this.Error(ex);
            }

            if (continueOnError)
            {
                Outcome = Result;
                Result = TaskResult.Succeeded;
                Trace.Info($"Updated step result (continue on error)");
            }

            if (!DeferOutcomeConclusion)
            {
                UpdateGlobalStepsContext();
            }
        }

private GetTokenOperation CreateOperation(
    VssTraceActivity traceActivity,
    IssuedToken failedToken,
    CancellationToken cancellationToken,
    out GetTokenOperation operationInProgress)
{
    operationInProgress = null;
    GetTokenOperation operation = null;
    lock (m_thisLock)
    {
        if (m_operations == null)
        {
            m_operations = new List<GetTokenOperation>();
        }

        // Grab the main operation which is doing the work (if any)
        if (m_operations.Count > 0)
        {
            operationInProgress = m_operations[0];

            // Use the existing completion source when creating the new operation
            operation = new GetTokenOperation(traceActivity, this, failedToken, cancellationToken, operationInProgress.CompletionSource);
        }
        else
        {
            operation = new GetTokenOperation(traceActivity, this, failedToken, cancellationToken);
        }

        m_operations.Add(operation);
    }

    return operation;
}

internal static String FormatValue(
    ISecretMasker secretMasker,
    Object value,
    ValueKind kind)
{
    switch (kind)
    {
        case ValueKind.Null:
            return ExpressionConstants.Null;

        case ValueKind.Boolean:
            return ((Boolean)value) ? ExpressionConstants.True : ExpressionConstants.False;

        case ValueKind.Number:
            var strNumber = ((Double)value).ToString(ExpressionConstants.NumberFormat, CultureInfo.InvariantCulture);
            return secretMasker != null ? secretMasker.MaskSecrets(strNumber) : strNumber;

        case ValueKind.String:
            // Mask secrets before string-escaping.
            var strValue = secretMasker != null ? secretMasker.MaskSecrets(value as String) : value as String;
            return $"'{StringEscape(strValue)}'";

        case ValueKind.Array:
        case ValueKind.Object:
            return kind.ToString();

        default: // Should never reach here.
            throw new NotSupportedException($"Unable to convert to realized expression. Unexpected value kind: {kind}");
    }
}

protected SequenceToken EvaluateSequenceToken(
    TemplateContext context,
    String expression,
    out Int32 bytes)
{
    var originalBytes = context.Memory.CurrentBytes;
    try
    {
        var tree = new ExpressionParser().CreateTree(expression, null, context.GetExpressionNamedValues(), context.ExpressionFunctions);
        var options = new EvaluationOptions
        {
            MaxMemory = context.Memory.MaxBytes,
        };
        var result = tree.Evaluate(context.TraceWriter.ToExpressionTraceWriter(), null, context, options);
        var templateToken = ConvertToTemplateToken(context, result);
        if (templateToken is SequenceToken sequence)
        {
            return sequence;
        }

        context.Error(this, TemplateStrings.ExpectedSequence());
        return CreateSequenceToken(context);
    }
    finally
    {
        bytes = context.Memory.CurrentBytes - originalBytes;
    }
}

