public Boolean TryFindService(String serviceType, Guid serviceIdentifier, out ServiceDefinition serviceDefinition)
        {
            EnsureDiskCacheLoaded();
            m_accessLock.EnterReadLock();

            try
            {
                Dictionary<Guid, ServiceDefinition> services = null;
                serviceDefinition = null;

                if (CacheDataExpired)
                {
                    return false;
                }

                if (m_services.TryGetValue(serviceType, out services))
                {
                    if (services.TryGetValue(serviceIdentifier, out serviceDefinition))
                    {
                        return true;
                    }
                }

                // Look in our cachedMisses to see if we can find it there.
                if (m_cachedMisses.Contains(BuildCacheMissString(serviceType, serviceIdentifier)))
                {
                    // We found an entry in cached misses so return true.
                    return true;
                }

                return false;
            }
            finally
            {
                m_accessLock.ExitReadLock();
            }
        }

private void AddExpression(
    String path,
    LiteralToken literal)
{
    var expressionLiteral = default(String);
    switch (literal.Type)
    {
        case TokenType.Null:
            expressionLiteral = ExpressionConstants.Null;
            break;

        case TokenType.Boolean:
            var booleanToken = literal as BooleanToken;
            expressionLiteral = ExpressionUtility.ConvertToParseToken(booleanToken.Value);
            break;

        case TokenType.Number:
            var numberToken = literal as NumberToken;
            expressionLiteral = ExpressionUtility.ConvertToParseToken(numberToken.Value);
            break;

        case TokenType.String:
            var stringToken = literal as StringToken;
            expressionLiteral = ExpressionUtility.ConvertToParseToken(stringToken.Value);
            break;

        default:
            throw new NotSupportedException($"Unexpected literal type '{literal.Type}'");
    }

    var parser = new ExpressionParser();
    var expressionString = $"{path} == {expressionLiteral}";
    var expression = parser.CreateTree(expressionString, null, s_matrixFilterNamedValues, null);
    m_expressions.Add(expression);
}

