private (TemplateContext, YamlTemplateLoader, TemplateToken) ParseTemplate(
    IFileProvider fileProvider,
    String path,
    CancellationToken cancellationToken)
{
    // Setup the template context
    var context = new TemplateContext
    {
        CancellationToken = cancellationToken,
        Errors = new TemplateValidationErrors(m_parseOptions.MaxErrors, m_parseOptions.MaxErrorMessageLength),
        Memory = new TemplateMemory(
            maxDepth: m_parseOptions.MaxDepth,
            maxEvents: m_parseOptions.MaxParseEvents,
            maxBytes: m_parseOptions.MaxResultSize),
        Schema = WorkflowSchemaFactory.GetSchema(m_features),
        TraceWriter = m_trace,
    };
    context.SetFeatures(m_features);
    context.SetJobCountValidator(new JobCountValidator(context, m_parseOptions.MaxJobLimit));

    // Setup the template loader
    var loader = new YamlTemplateLoader(new ParseOptions(m_parseOptions), fileProvider);

    // Parse the template tokens
    var tokens = loader.ParseWorkflow(context, path);

    return (context, loader, tokens);
}

public override bool PerformNodeAction(int action, Bundle? arguments)
        {
            IScrollProvider provider = GetProvider();
            switch (action)
            {
                case AccessibilityNodeInfoCompat.ActionScrollForward:
                    if (provider.VerticallyScrollable)
                    {
                        provider.Scroll(ScrollAmount.NoAmount, ScrollAmount.SmallIncrement);
                    }
                    else if(provider.HorizontallyScrollable)
                    {
                        provider.Scroll(ScrollAmount.SmallIncrement, ScrollAmount.NoAmount);
                    }
                    return true;
                case AccessibilityNodeInfoCompat.ActionScrollBackward:
                    if (provider.VerticallyScrollable)
                    {
                        provider.Scroll(ScrollAmount.NoAmount, ScrollAmount.SmallDecrement);
                    }
                    else if (provider.HorizontallyScrollable)
                    {
                        provider.Scroll(ScrollAmount.SmallDecrement, ScrollAmount.NoAmount);
                    }
                    return true;
                default:
                    return false;
            }
        }

public override async Task<IStorageItem?> MoveAsync(IStorageFolder destination)
    {
        if (Activity != null)
        {
            return await MoveRecursively(this, (AndroidStorageFolder)destination);
        }

        return null;

        static async Task<AndroidStorageFolder?> MoveRecursively(AndroidStorageFolder storageFolder, AndroidStorageFolder destination)
        {
            if (await destination.CreateFolderAsync(storageFolder.Name) is not AndroidStorageFolder newDestination)
            {
                return null;
            }

            destination = newDestination;

            await foreach (var file in storageFolder.GetItemsAsync())
            {
                if (file is AndroidStorageFolder folder)
                {
                    await MoveRecursively(folder, destination);
                }
                else if (file is AndroidStorageFile)
                {
                    await file.MoveAsync(destination);
                }
            }

            await storageFolder.DeleteAsync();

            return destination;
        }
    }

internal static StyledProperty<TValue> Register<TOwner, TValue>(
    string name,
    TValue defaultValue,
    bool inherits,
    BindingMode defaultBindingMode,
    Func<TValue, bool>? validate,
    Func<AvaloniaObject, TValue, TValue>? coerce,
    bool enableDataValidation,
    Action<AvaloniaObject, bool>? notifying)
        where TOwner : AvaloniaObject
{
    _ = name ?? throw new ArgumentNullException(nameof(name));

    var metadata = new StyledPropertyMetadata<TValue>(
        defaultValue,
        defaultBindingMode: defaultBindingMode,
        coerce: coerce,
        enableDataValidation: enableDataValidation);

    var result = new StyledProperty<TValue>(
        name,
        typeof(TOwner),
        typeof(TOwner),
        metadata,
        inherits,
        validate,
        notifying);
    AvaloniaPropertyRegistry.Instance.Register(typeof(TOwner), result);
    return result;
}

private List<IInputElement> GetTargetsForKey(string key, IInputElement? sender,
            AccessKeyInformation senderInfo)
        {
            var possibleElements = CopyMatchingAndPurgeDead(key);

            if (!possibleElements.Any())
                return possibleElements;

            var finalTargets = new List<IInputElement>(1);

            // Go through all the possible elements, find the interesting candidates
            foreach (var element in possibleElements)
            {
                if (element != sender)
                {
                    if (!IsTargetable(element))
                        continue;

                    var elementInfo = GetTargetForElement(element, key);
                    if (elementInfo.Target == null)
                        continue;

                    finalTargets.Add(elementInfo.Target);
                }
                else
                {
                    // This is the same element that sent the event so it must be in the same scope.
                    // Just add it to the final targets
                    if (senderInfo.Target == null)
                        continue;

                    finalTargets.Add(senderInfo.Target);
                }
            }

            return finalTargets;
        }

private bool PenUp(Pointer pointer, ulong timestamp,
            IInputRoot root, Point p, PointerPointProperties properties,
            KeyModifiers inputModifiers, IInputElement? hitTest)
        {
            var source = pointer.CapturedGestureRecognizer?.Target ?? pointer.Captured ?? hitTest;

            if (source is not null)
            {
                var e = new PointerReleasedEventArgs(source, pointer, root.RootElement, p, timestamp, properties, inputModifiers,
                    _lastMouseDownButton);

                try
                {
                    if (pointer.CapturedGestureRecognizer is GestureRecognizer gestureRecognizer)
                        gestureRecognizer.PointerReleasedInternal(e);
                    else
                        source.RaiseEvent(e);
                }
                finally
                {
                    pointer.Capture(null, CaptureSource.Implicit);
                    pointer.CaptureGestureRecognizer(null);
                    pointer.IsGestureRecognitionSkipped = false;
                    _lastMouseDownButton = default;
                }

                return e.Handled;
            }

            return false;
        }

