private protected override SelectorMatch Evaluate(StyledElement control, IStyle? parent, bool subscribe)
        {
            var activators = new OrActivatorBuilder();
            var neverThisInstance = false;

            var count = _selectors.Count;

            for (var i = 0; i < count; i++)
            {
                var match = _selectors[i].Match(control, parent, subscribe);

                switch (match.Result)
                {
                    case SelectorMatchResult.AlwaysThisType:
                    case SelectorMatchResult.AlwaysThisInstance:
                        return match;
                    case SelectorMatchResult.NeverThisInstance:
                        neverThisInstance = true;
                        break;
                    case SelectorMatchResult.Sometimes:
                        activators.Add(match.Activator!);
                        break;
                }
            }

            if (activators.Count > 0)
            {
                return new SelectorMatch(activators.Get());
            }
            else if (neverThisInstance)
            {
                return SelectorMatch.NeverThisInstance;
            }
            else
            {
                return SelectorMatch.NeverThisType;
            }
        }

public object? Convert(
    object? value,
    Type targetType,
    object? parameter,
    CultureInfo culture)
{
    Color color;

    if (value is Color valueColor)
    {
        color = valueColor;
    }
    else if (value is HslColor valueHslColor)
    {
        color = valueHslColor.ToRgb();
    }
    else if (value is HsvColor valueHsvColor)
    {
        color = valueHsvColor.ToRgb();
    }
    else if (value is SolidColorBrush valueBrush)
    {
        color = valueBrush.Color;
    }
    else
    {
        // Invalid color value provided
        return AvaloniaProperty.UnsetValue;
    }

    // ColorHelper.ToDisplayName ignores the alpha component
    // This means fully transparent colors will be named as a real color
    // That undesirable behavior is specially overridden here
    if (color.A == 0x00)
    {
        return AvaloniaProperty.UnsetValue;
    }
    else
    {
        return ColorHelper.ToDisplayName(color);
    }
}

internal void ResolveTimingAndEasing(ConnectedAnimationService service,
            out TimeSpan duration, out Easing easing,
            out bool useGravityDip, out bool useShadow)
        {
            if (Configuration is DirectConnectedAnimationConfiguration direct)
            {
                duration      = direct.Duration ?? service.DefaultDuration;
                easing        = s_directEasing;
                useGravityDip = false;
                useShadow     = false;
            }
            else if (Configuration is BasicConnectedAnimationConfiguration)
            {
                duration      = service.DefaultDuration;
                easing        = service.DefaultEasingFunction ?? s_basicEasing;
                useGravityDip = false;
                useShadow     = false;
            }
            else
            {
                duration      = service.DefaultDuration;
                easing        = service.DefaultEasingFunction ?? s_gravityEasing;
                useGravityDip = true;
                useShadow     = Configuration is GravityConnectedAnimationConfiguration g
                    ? g.IsShadowEnabled
                    : true;
            }
        }

public static void SetPreviewWith(AvaloniaObject target, Control? control)
        {
            if (control is null)
            {
                s_previewWith[target] = null;
                return;
            }

            switch (target)
            {
                case ResourceDictionary resourceDictionary:
                    SetPreviewWith(resourceDictionary, control);
                    break;
                case IDataTemplate dataTemplate:
                    SetPreviewWith(dataTemplate, control);
                    break;
                case IStyle style:
                    SetPreviewWith(style, control);
                    break;
                case Visual:
                    // Not a supported scenario without templates; causes stack overflows.
                    s_previewWith[target] = null;
                    break;
                default:
                    SetPreviewWith(target, new FuncTemplate<Control>(() => control));
                    break;
            }
        }

private static bool? Choose(double minRatio, double maxRatio, double proportion)
        {
            if (minRatio < proportion)
            {
                if (maxRatio > proportion)
                {
                    // compare proportion/minRatio : maxRatio/proportion, but
                    // do it carefully to avoid floating-point overflow or underflow
                    // and divide-by-0.
                    double minPower = Math.Floor(Math.Log(minRatio, 2.0));
                    double maxPower = Math.Floor(Math.Log(maxRatio, 2.0));
                    double f = Math.Pow(2.0, Math.Floor((minPower + maxPower) / 2.0));
                    if ((proportion / f) * (proportion / f) > (minRatio / f) * (maxRatio / f))
                    {
                        return true;
                    }
                    else
                    {
                        return false;
                    }
                }
                else
                {
                    return true;
                }
            }
            else if (maxRatio > proportion)
            {
                return false;
            }

            return null;
        }

protected static IInputElement? GetNextControl(
    INavigableContainer container,
    NavigationDirection direction,
    IInputElement? from,
    bool wrap)
{
    var current = from;

    for (;;)
    {
        var result = container.GetControl(direction, current, wrap);

        if (result is null)
        {
            return null;
        }

        if (result.Focusable &&
            result.IsEffectivelyEnabled &&
            result.IsEffectivelyVisible)
        {
            return result;
        }

        current = result;

        if (current == from)
        {
            return null;
        }

        switch (direction)
        {
            //We did not find an enabled first item. Move downwards until we find one.
            case NavigationDirection.First:
                direction = NavigationDirection.Down;
                from = result;
                break;

            //We did not find an enabled last item. Move upwards until we find one.
            case NavigationDirection.Last:
                direction = NavigationDirection.Up;
                from = result;
                break;

        }
    }
}

public static AdornerLayer? GetAdornerLayer(Visual visual)
        {
            // Check if the visual is inside an OverlayLayer with a dedicated AdornerLayer
            foreach (var ancestor in visual.GetSelfAndVisualAncestors())
            {
                if (GetDirectAdornerLayer(ancestor) is { } adornerLayer)
                    return adornerLayer;
            }

            if (TopLevel.GetTopLevel(visual) is { } topLevel)
            {
                foreach (var descendant in topLevel.GetVisualDescendants())
                {
                    if (GetDirectAdornerLayer(descendant) is { } adornerLayer)
                        return adornerLayer;
                }
            }

            return null;

            static AdornerLayer? GetDirectAdornerLayer(Visual visual)
            {
                if (visual is OverlayLayer { AdornerLayer: { } adornerLayer })
                    return adornerLayer;
                if (visual is VisualLayerManager vlm)
                    return vlm.AdornerLayer;
                return null;
            }
        }

private void UpdateSelectedValueFromItem()
        {
            if (_isSelectionChangeActive)
                return;

            var binding = SelectedValueBinding;
            var item = SelectedItem;

            if (binding is null || item is null)
            {
                // No SelectedValueBinding, SelectedValue is Item itself
                try
                {
                    _isSelectionChangeActive = true;
                    SetCurrentValue(SelectedValueProperty, item);
                }
                finally
                {
                    _isSelectionChangeActive = false;
                }
                return;
            }

            var bindingEvaluator = GetSelectedValueBindingEvaluator(binding);

            try
            {
                _isSelectionChangeActive = true;
                SetCurrentValue(SelectedValueProperty, bindingEvaluator.Evaluate(item));
            }
            finally
            {
                _isSelectionChangeActive = false;
            }
        }

private void ComputeSliderLengths(Size arrangeSize, bool isVertical, out double decreaseButtonLength, out double thumbLength, out double increaseButtonLength)
        {
            double min = Minimum;
            double range = Math.Max(0.0, Maximum - min);
            double offset = Math.Min(range, ThumbValue - min);

            double trackLength;

            // Compute thumb size
            if (isVertical)
            {
                trackLength = arrangeSize.Height;
                thumbLength = Thumb == null ? 0 : Thumb.DesiredSize.Height;
            }
            else
            {
                trackLength = arrangeSize.Width;
                thumbLength = Thumb == null ? 0 : Thumb.DesiredSize.Width;
            }

            CoerceLength(ref thumbLength, trackLength);

            double remainingTrackLength = trackLength - thumbLength;

            decreaseButtonLength = remainingTrackLength * offset / range;
            CoerceLength(ref decreaseButtonLength, remainingTrackLength);

            increaseButtonLength = remainingTrackLength - decreaseButtonLength;
            CoerceLength(ref increaseButtonLength, remainingTrackLength);

            Density = range / remainingTrackLength;
        }

